={
  "model": "openai/gpt-4o",
  "messages": [
    {
      "role": "system",
      "content": "You are an expert in analyzing Google search trends in the US market, with deep mastery of Google Trends, American consumer search behavior, and the seasonal and cultural dynamics that influence search volumes in the United States.\n\nI want you to analyze current and emerging Google search trends in the US market. For each topic or query I explore with you, you must:\n* Contextualize the trend within the specific US market framework (regions, demographics, seasonality)\n* Identify interest spikes and triggering factors (events, news, pop culture, economic cycles)\n* Spot emerging opportunities before they reach peak popularity\n* Compare variations between US states or regions when relevant\n* Distinguish short-lived trends from durable underlying signals\n* Provide actionable insights based on these data (content, positioning, timing)\n\nUse precise vocabulary from the fields of search marketing and consumer insights. Support your analysis with concrete data, real examples, and temporal comparisons whenever available."
    },
    {
      "role": "user",
      "content": "Analyze this topic: {{ $('⚙️ Config').item.json.topic }} products (without brands) with an increase in search in last month. Extract 5 main keywords.\n\nReturn ONLY a valid JSON object with this exact format: {\"keywords\": [\"keyword1\", \"keyword2\", \"keyword3\", \"keyword4\", \"keyword5\"]}"
    }
  ],
  "response_format": {"type": "json_object"},
  "temperature": 0.3,
  "max_tokens": 200
}

parameters.jsCode:
// Parse la réponse OpenRouter/GPT et retourne un item par keyword
const raw = items[0].json;

// 1. Extraire le contenu de la réponse OpenAI
const content = raw.choices?.[0]?.message?.content;
if (!content) {
  throw new Error('Réponse OpenRouter vide. Clés: ' + Object.keys(raw).join(', '));
}

// 2. Parser le JSON
let parsed;
try {
  parsed = JSON.parse(content.trim());
} catch (e1) {
  const m = content.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('Aucun JSON dans la réponse GPT: ' + content.substring(0, 300));
  try { parsed = JSON.parse(m[0]); }
  catch (e2) { throw new Error('JSON invalide: ' + e2.message); }
}

// 3. Extraire les keywords
const keywords = parsed.keywords;
if (!keywords || !keywords.length) {
  throw new Error('Aucun keyword trouvé. Clés: ' + Object.keys(parsed).join(', '));
}

// 4. Récupérer la config
let config = {};
try { config = $('⚙️ Config').first().json; }
catch (e) { config = { topic: '', serpApiKey: '', targetCountry: 'us' }; }

// 5. Retourner un item par keyword (max 5)
return keywords.slice(0, 5).map((kw, i) => ({
  json: {
    index:         i + 1,
    main_keyword:  typeof kw === 'string' ? kw : (kw.keyword || String(kw)),
    topic:         config.topic         || '',
    serpApiKey:    config.serpApiKey    || '',
    targetCountry: config.targetCountry || 'us'
  }
}));

// Analyser les données Google Trends + extraire les séries pour les graphiques
const item = items[0].json;
const timeline = item.interest_over_time?.timeline_data || [];

if (!timeline.length) {
  return [{ json: {
    ...item,
    trend_5y: 'no_data', trend_12m: 'no_data', trend_90d: 'no_data',
    trend_ok: false, trend_peak: 0, trend_avg: 0,
    chart_5y:  { labels: [], data: [] },
    chart_12m: { labels: [], data: [] },
    chart_3m:  { labels: [], data: [] }
  }}];
}

// Valeurs numériques + labels de dates
const values = timeline.map(t => t.values?.[0]?.extracted_value || 0);
const dates  = timeline.map(t => t.date);

// Évaluation de tendance (premier tiers vs dernier tiers)
function evalTrend(vals) {
  const third = Math.floor(vals.length / 3) || 1;
  const start = vals.slice(0, third).reduce((a, b) => a + b, 0) / third;
  const end   = vals.slice(-third).reduce((a, b) => a + b, 0) / third;
  const ratio = end / (start || 1);
  if (ratio >= 1.15) return 'growing';
  if (ratio <= 0.85) return 'declining';
  return 'stable';
}

const t5y  = evalTrend(values);
const t12m = evalTrend(values.slice(-52));   // ~12 mois (hebdo)
const t90d = evalTrend(values.slice(-13));   // ~3 mois  (hebdo)

const trend_ok = t5y !== 'declining' && t12m !== 'declining';

// Données graphiques pour les 3 fenêtres temporelles
const chart_5y  = { labels: dates,           data: values };
const chart_12m = { labels: dates.slice(-52), data: values.slice(-52) };
const chart_3m  = { labels: dates.slice(-13), data: values.slice(-13) };

return [{ json: {
  ...item,
  trend_5y:   t5y,
  trend_12m:  t12m,
  trend_90d:  t90d,
  trend_ok,
  trend_peak: Math.max(...values),
  trend_avg:  Math.round(values.reduce((a, b) => a + b, 0) / values.length),
  chart_5y,
  chart_12m,
  chart_3m
}}];

// Assembler toutes les données en un rapport final
const item = items[0].json;

// Extraire les concurrents Shopify depuis les résultats Google
const organicResults = item.organic_results || [];
const competitors = organicResults.slice(0, 5).map(r => ({
  domain: r.displayed_link?.replace(/^www\./, '') || r.link,
  title:  r.title,
  url:    r.link,
  bestSellingUrl: (() => {
    try {
      const domain = new URL(r.link).origin;
      return domain + '/collections/all?sort_by=best-selling';
    } catch { return ''; }
  })()
}));

// Extraire les annonces Google Ads si disponibles
const ads = item.ads || [];
const cpcData = ads.slice(0, 3).map(a => ({
  title:       a.title,
  displayLink: a.displayed_link,
  description: a.description
}));

// Rapport final structuré
const report = {
  // Infos produit
  product_name:    item.name,
  category:        item.category,
  niche:           item.niche,
  competition:     item.competition,
  buyer_intent:    item.buyer_intent,
  evergreen_reason: item.evergreen_reason,
  aliexpress_query: item.aliexpress_query,

  // Keywords
  main_keyword: item.main_keyword,
  keywords:     (item.keywords || []).join(', '),

  // Google Trends
  trend_5y:   item.trend_5y,
  trend_12m:  item.trend_12m,
  trend_90d:  item.trend_90d,
  trend_peak: item.trend_peak,
  trend_avg:  item.trend_avg,

  // Concurrents Shopify
  competitor_1: competitors[0]?.domain || '',
  competitor_1_best: competitors[0]?.bestSellingUrl || '',
  competitor_2: competitors[1]?.domain || '',
  competitor_2_best: competitors[1]?.bestSellingUrl || '',
  competitor_3: competitors[2]?.domain || '',
  competitor_3_best: competitors[2]?.bestSellingUrl || '',
  competitor_4: competitors[3]?.domain || '',
  competitor_4_best: competitors[3]?.bestSellingUrl || '',
  competitor_5: competitors[4]?.domain || '',
  competitor_5_best: competitors[4]?.bestSellingUrl || '',

  // Meta
  analysed_at: new Date().toISOString().split('T')[0],
  decision:    'pending',
  notes:       ''
};

return [{ json: report }];

// Assembler les 5 keywords avec leurs données Trends
const allKeywords = items[0].json.keywords_data || [];

return [{
  json: {
    success: true,
    topic:   allKeywords[0]?.topic || '',
    count:   allKeywords.length,
    keywords: allKeywords.map(k => ({
      keyword:    k.main_keyword,
      trend_5y:   k.trend_5y,
      trend_12m:  k.trend_12m,
      trend_3m:   k.trend_90d,
      trend_ok:   k.trend_ok,
      trend_peak: k.trend_peak,
      trend_avg:  k.trend_avg,
      chart_5y:   k.chart_5y   || { labels: [], data: [] },
      chart_12m:  k.chart_12m  || { labels: [], data: [] },
      chart_3m:   k.chart_3m   || { labels: [], data: [] }
    }))
  }
}];
